INSERT INTO public.recipes VALUES
	('a0000001-0000-0000-0000-000000000001', 'Chicken Biryani', 'Indian', 'Hard', 30, 60, 4, '[{"instruction": "Wash and soak 2 cups basmati rice for 30 minutes. Drain well.", "step_number": 1, "time_minutes": 30}, {"instruction": "Marinate chicken pieces in yogurt, biryani masala, red chilli powder, ginger-garlic paste and salt for at least 1 hour.", "step_number": 2, "time_minutes": 60}, {"instruction": "Parboil the soaked rice with whole spices (bay leaf, cloves, cardamom, cinnamon) until 70% cooked. Drain and set aside.", "step_number": 3, "time_minutes": 15}, {"instruction": "Heat ghee in a heavy-bottomed pot. Fry thinly sliced onions until golden brown (birista). Remove half and reserve for garnish. Add marinated chicken and cook on high heat for 5 minutes.", "step_number": 4, "time_minutes": 20}, {"instruction": "Layer parboiled rice over the chicken. Top with fried onions, saffron milk, mint leaves and a drizzle of ghee. Seal pot with foil and a tight lid.", "step_number": 5, "time_minutes": 5}, {"instruction": "Cook on dum (low flame) for 25 minutes until chicken is fully cooked and rice is tender. Rest for 10 minutes before opening.", "step_number": 6, "time_minutes": 35}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000002', 'Butter Chicken', 'Indian', 'Medium', 20, 40, 4, '[{"instruction": "Marinate chicken in yogurt, lemon juice, turmeric, red chilli powder, garam masala and ginger-garlic paste for 30 minutes.", "step_number": 1, "time_minutes": 30}, {"instruction": "Grill or pan-fry marinated chicken until slightly charred. Set aside.", "step_number": 2, "time_minutes": 10}, {"instruction": "Make makhani sauce: heat butter, sauté onions until golden. Add ginger-garlic paste, tomatoes, cashews and cook until mushy. Cool and blend smooth.", "step_number": 3, "time_minutes": 20}, {"instruction": "Strain the sauce back into the pan. Add cream, honey, kasuri methi, garam masala and salt. Simmer 10 minutes.", "step_number": 4, "time_minutes": 10}, {"instruction": "Add grilled chicken to the sauce. Simmer for 5–7 minutes until chicken absorbs the flavours.", "step_number": 5, "time_minutes": 7}, {"instruction": "Finish with a swirl of fresh cream and butter. Serve hot with naan or steamed rice.", "step_number": 6, "time_minutes": 3}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000003', 'Palak Paneer', 'Indian', 'Easy', 15, 25, 3, '[{"instruction": "Blanch 500g fresh spinach in boiling salted water for 2 minutes. Immediately plunge into ice water. Drain and blend to a smooth purée.", "step_number": 1, "time_minutes": 10}, {"instruction": "Cube 200g paneer and lightly pan-fry in 1 tsp oil until golden. Soak in warm water to keep soft.", "step_number": 2, "time_minutes": 5}, {"instruction": "In the same pan, heat 2 tbsp oil. Splutter cumin, add finely chopped onion, ginger-garlic paste and cook until golden.", "step_number": 3, "time_minutes": 8}, {"instruction": "Add chopped tomato, all dry spices (coriander, cumin, garam masala, salt) and cook until oil separates.", "step_number": 4, "time_minutes": 7}, {"instruction": "Add spinach purée and simmer for 5 minutes. Stir in paneer, a splash of cream and adjust seasoning.", "step_number": 5, "time_minutes": 5}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000004', 'Dal Makhani', 'Indian', 'Medium', 480, 60, 6, '[{"instruction": "Soak 1 cup whole black lentils (urad dal) and 1/4 cup kidney beans overnight in cold water.", "step_number": 1, "time_minutes": 480}, {"instruction": "Pressure cook soaked lentils with salt and water for 45 minutes on medium heat (or until very soft).", "step_number": 2, "time_minutes": 45}, {"instruction": "In a heavy pan, melt 2 tbsp butter with oil. Sauté finely diced onion until caramelised. Add ginger-garlic paste and cook 2 minutes.", "step_number": 3, "time_minutes": 12}, {"instruction": "Add tomato purée, all spices (coriander, cumin, garam masala, chilli powder) and cook 10 minutes until masala deepens in colour.", "step_number": 4, "time_minutes": 10}, {"instruction": "Add cooked lentils and stir well. Simmer on very low heat for 30 minutes, stirring every few minutes. The longer it cooks, the better.", "step_number": 5, "time_minutes": 30}, {"instruction": "Finish with fresh cream, a knob of butter and kasuri methi. Adjust salt and serve with naan.", "step_number": 6, "time_minutes": 5}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000005', 'Tandoori Chicken', 'Indian', 'Medium', 30, 25, 4, '[{"instruction": "Score chicken pieces deeply with a sharp knife to allow marinade to penetrate.", "step_number": 1, "time_minutes": 5}, {"instruction": "First marinade: rub chicken with lemon juice, salt and chilli. Let rest 30 minutes.", "step_number": 2, "time_minutes": 30}, {"instruction": "Second marinade: mix thick yogurt, tandoori masala, ginger-garlic paste, red food colour (optional), chilli powder and mustard oil. Coat chicken thoroughly.", "step_number": 3, "time_minutes": 5}, {"instruction": "Marinate in the fridge for at least 4 hours (overnight is ideal).", "step_number": 4, "time_minutes": 240}, {"instruction": "Cook at 220°C (430°F) for 20–25 minutes, turning halfway. Finish under grill for 3 minutes for char.", "step_number": 5, "time_minutes": 25}, {"instruction": "Rest 5 minutes. Serve with mint chutney, sliced onion rings and lemon wedges.", "step_number": 6, "time_minutes": 5}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000006', 'Samosa', 'Indian', 'Hard', 60, 30, 12, '[{"instruction": "Make dough: combine flour, carom seeds, oil and salt. Add warm water gradually to form a firm dough. Rest 20 minutes.", "step_number": 1, "time_minutes": 20}, {"instruction": "Filling: boil potatoes until soft, mash coarsely. Stir-fry with oil, cumin, peas, green chillies, ginger, spices and amchur. Cool completely.", "step_number": 2, "time_minutes": 20}, {"instruction": "Divide dough into balls. Roll each into an oval. Cut in half to get two semi-circles.", "step_number": 3, "time_minutes": 10}, {"instruction": "Form a cone from each semi-circle (use flour-water paste to seal seam). Fill with potato mixture. Seal the open edge firmly.", "step_number": 4, "time_minutes": 20}, {"instruction": "Deep fry samosas in oil at 160°C (325°F) for 8–10 minutes turning frequently until golden and crisp. Do not fry on high heat — the pastry will blister.", "step_number": 5, "time_minutes": 15}, {"instruction": "Drain on paper. Serve with mint chutney and tamarind chutney.", "step_number": 6, "time_minutes": 5}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('b0000002-0000-0000-0000-000000000002', 'Hot and Sour Soup', 'Chinese', 'Easy', 15, 20, 4, '[{"instruction": "Bring chicken stock to a simmer with tofu, mushrooms, bamboo.", "step_number": 1}, {"instruction": "Add vinegar, soy sauce, white pepper for heat and tang.", "step_number": 2}, {"instruction": "Thicken with cornstarch slurry; stream in beaten egg.", "step_number": 3}]', 'https://images.example.com/hot-sour-soup.jpg', false, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000007', 'Butter Naan', 'Indian', 'Medium', 120, 15, 6, '[{"instruction": "Combine flour, yeast, sugar, salt, yogurt and oil. Add warm water to form a soft dough. Knead 8 minutes until smooth.", "step_number": 1, "time_minutes": 10}, {"instruction": "Cover and let rise in a warm place for 1–2 hours until doubled.", "step_number": 2, "time_minutes": 120}, {"instruction": "Divide into 6 balls. Roll each into an oval about 3mm thick.", "step_number": 3, "time_minutes": 10}, {"instruction": "Heat a heavy tawa or cast iron skillet on high. Brush naan with water on one side, press water-side down onto skillet.", "step_number": 4, "time_minutes": 2}, {"instruction": "When bubbles form (about 1 minute), flip skillet over a direct gas flame to char the top, or use a broiler for 2 minutes.", "step_number": 5, "time_minutes": 3}, {"instruction": "Brush immediately with melted butter and sprinkle with fresh coriander. Wrap in cloth to keep soft.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000008', 'Aloo Gobi', 'Indian', 'Easy', 10, 30, 4, '[{"instruction": "Cut 300g potatoes into 1-inch cubes. Break 1 medium cauliflower into florets. Pat both dry.", "step_number": 1, "time_minutes": 10}, {"instruction": "Heat 3 tbsp oil in a kadai. Add cumin seeds and let splutter. Add potatoes and fry on medium-high for 5 minutes.", "step_number": 2, "time_minutes": 7}, {"instruction": "Add cauliflower florets and toss with potatoes. Sprinkle turmeric and salt. Cover and cook 10 minutes, stirring occasionally.", "step_number": 3, "time_minutes": 10}, {"instruction": "Uncover, add ginger-garlic paste, chopped green chillies, coriander powder, cumin powder and garam masala. Toss well.", "step_number": 4, "time_minutes": 3}, {"instruction": "Cook uncovered another 8–10 minutes until potatoes are tender and edges are lightly golden. Adjust salt.", "step_number": 5, "time_minutes": 10}, {"instruction": "Garnish with fresh coriander leaves. Serve with roti or rice.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000009', 'Chana Masala', 'Indian', 'Easy', 480, 30, 4, '[{"instruction": "Soak 1.5 cups dried chickpeas overnight. Pressure cook with salt until tender (about 20 minutes). Reserve cooking liquid.", "step_number": 1, "time_minutes": 480}, {"instruction": "Heat 2 tbsp oil. Add bay leaf, cloves and cinnamon. Sauté onions until deep golden brown — this step is crucial for flavour.", "step_number": 2, "time_minutes": 12}, {"instruction": "Add ginger-garlic paste, chopped tomatoes, chana masala powder, coriander, cumin and turmeric. Cook until oil separates.", "step_number": 3, "time_minutes": 10}, {"instruction": "Add cooked chickpeas along with some cooking liquid. Mash a few chickpeas into the gravy to thicken.", "step_number": 4, "time_minutes": 5}, {"instruction": "Simmer 10–15 minutes. Finish with amchur powder, garam masala, chopped coriander and lemon juice.", "step_number": 5, "time_minutes": 15}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000001-0000-0000-0000-000000000010', 'Paneer Tikka', 'Indian', 'Medium', 40, 15, 4, '[{"instruction": "Cut 250g paneer into 1.5-inch cubes. Cut bell peppers and onion into similar chunks.", "step_number": 1, "time_minutes": 10}, {"instruction": "Marinade: whisk together thick yogurt, ginger-garlic paste, tikka masala, chilli powder, cumin, oil and salt. Coat paneer and vegetables well.", "step_number": 2, "time_minutes": 5}, {"instruction": "Marinate for at least 30 minutes (preferably 2 hours in the fridge).", "step_number": 3, "time_minutes": 30}, {"instruction": "Thread onto skewers, alternating paneer, peppers and onion.", "step_number": 4, "time_minutes": 5}, {"instruction": "Grill at 220°C / under broiler for 10–12 minutes, turning once, until slightly charred at edges.", "step_number": 5, "time_minutes": 12}, {"instruction": "Squeeze lemon juice over and serve with mint chutney and sliced red onion.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000002-0000-0000-0000-000000000011', 'Fried Rice', 'Chinese', 'Easy', 10, 15, 4, '[{"instruction": "Use day-old cold cooked rice — fresh rice is too moist and clumps.", "step_number": 1, "time_minutes": 0}, {"instruction": "Beat 3 eggs with a pinch of salt. Scramble in a wok with 1 tbsp oil over high heat, breaking into small curds. Set aside.", "step_number": 2, "time_minutes": 3}, {"instruction": "Add 2 tbsp oil to the hot wok. Stir-fry diced carrots and peas for 2 minutes. Add chopped spring onions.", "step_number": 3, "time_minutes": 3}, {"instruction": "Add cold rice and spread across the wok. Let sit 30 seconds for slight crust to form, then toss vigorously.", "step_number": 4, "time_minutes": 4}, {"instruction": "Season with soy sauce, white pepper, oyster sauce and sesame oil. Fold in scrambled eggs.", "step_number": 5, "time_minutes": 3}, {"instruction": "Toss until heated through and evenly coated. Garnish with spring onion greens.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000002-0000-0000-0000-000000000012', 'Sweet & Sour Chicken', 'Chinese', 'Medium', 20, 25, 4, '[{"instruction": "Cut chicken breast into bite-size pieces. Coat in cornstarch, egg and a pinch of salt.", "step_number": 1, "time_minutes": 10}, {"instruction": "Deep fry chicken in 180°C oil until golden and crispy (5–6 minutes). Drain on paper towels. Fry in batches to avoid crowding.", "step_number": 2, "time_minutes": 12}, {"instruction": "Prepare sauce: mix ketchup, rice vinegar, soy sauce, sugar, water and cornstarch in a bowl.", "step_number": 3, "time_minutes": 3}, {"instruction": "In a separate pan, stir-fry chunks of bell peppers (red and green) and pineapple chunks for 2 minutes.", "step_number": 4, "time_minutes": 3}, {"instruction": "Pour sauce into pan and cook, stirring, until thickened (about 2 minutes).", "step_number": 5, "time_minutes": 2}, {"instruction": "Add crispy chicken and toss to coat evenly. Serve immediately with steamed rice.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('b0000003-0000-0000-0000-000000000001', 'Tiramisu', 'Italian', 'Medium', 30, 0, 8, '[{"instruction": "Whisk egg yolks with sugar; fold in mascarpone.", "step_number": 1}, {"instruction": "Whip cream to soft peaks; fold into mascarpone mix.", "step_number": 2}, {"instruction": "Dip ladyfingers in espresso; layer with cream.", "step_number": 3}, {"instruction": "Refrigerate 6+ hours; dust with cocoa before serving.", "step_number": 4, "time_minutes": 360}]', 'https://images.example.com/tiramisu.jpg', false, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000004-0000-0000-0000-000000000004', 'Guacamole', 'Mexican', 'Easy', 10, 0, 4, '[{"instruction": "Mash ripe avocados with lime juice and salt.", "step_number": 1}, {"instruction": "Fold in diced onion, tomato, jalapeño, cilantro.", "step_number": 2}, {"instruction": "Taste and adjust salt and acid.", "step_number": 3}]', 'https://images.example.com/guacamole.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('a0000002-0000-0000-0000-000000000013', 'Kung Pao Chicken', 'Chinese', 'Medium', 15, 15, 4, '[{"instruction": "Dice chicken into small cubes. Marinate with soy sauce, cornstarch and Shaoxing wine for 15 minutes.", "step_number": 1, "time_minutes": 15}, {"instruction": "Prepare kung pao sauce: mix soy sauce, dark vinegar, sugar, sesame oil and cornstarch.", "step_number": 2, "time_minutes": 5}, {"instruction": "Heat wok until smoking. Fry dried red chillies and Sichuan peppercorns in oil for 30 seconds until fragrant.", "step_number": 3, "time_minutes": 2}, {"instruction": "Add marinated chicken, spread and cook without stirring for 1 minute, then toss until cooked.", "step_number": 4, "time_minutes": 4}, {"instruction": "Add sliced spring onions, minced garlic and ginger. Pour sauce over and toss to coat.", "step_number": 5, "time_minutes": 3}, {"instruction": "Fold in roasted peanuts. Plate and garnish with more Sichuan peppercorn powder.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000002-0000-0000-0000-000000000014', 'Dumplings (Jiaozi)', 'Chinese', 'Hard', 60, 15, 4, '[{"instruction": "Dough: add boiling water gradually to flour and mix until cool enough to knead. Rest 30 minutes under a damp cloth.", "step_number": 1, "time_minutes": 30}, {"instruction": "Filling: combine minced pork, napa cabbage (salted, squeezed dry), ginger, soy sauce, sesame oil, egg and white pepper.", "step_number": 2, "time_minutes": 15}, {"instruction": "Roll dough into a rope, cut into small pieces. Roll each into a thin round wrapper (~8cm diameter).", "step_number": 3, "time_minutes": 20}, {"instruction": "Place 1 tsp filling in the centre of each wrapper. Fold and pleat the edge to seal tightly.", "step_number": 4, "time_minutes": 15}, {"instruction": "Boil in salted water until dumplings float and skins are translucent, about 6–8 minutes. Or pan-fry until bottoms are golden.", "step_number": 5, "time_minutes": 8}, {"instruction": "Serve with dipping sauce: soy sauce, rice vinegar, chilli oil and sesame seeds.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000002-0000-0000-0000-000000000015', 'Hot & Sour Soup', 'Chinese', 'Easy', 15, 20, 4, '[{"instruction": "Prepare all toppings: cut tofu into thin strips, slice mushrooms (shiitake and wood ear), shred bamboo shoots and carrot.", "step_number": 1, "time_minutes": 15}, {"instruction": "Bring 4 cups chicken stock to a boil. Add mushrooms and bamboo shoots. Simmer 5 minutes.", "step_number": 2, "time_minutes": 7}, {"instruction": "Add tofu strips and carrot. Season with soy sauce, white pepper, rice vinegar and a touch of dark soy.", "step_number": 3, "time_minutes": 5}, {"instruction": "Mix 3 tbsp cornstarch with cold water. Stream into soup while stirring to thicken.", "step_number": 4, "time_minutes": 3}, {"instruction": "Beat 2 eggs. Pour in a thin stream while stirring the soup in circles to create silky egg ribbons.", "step_number": 5, "time_minutes": 2}, {"instruction": "Finish with sesame oil, more white pepper and sliced spring onions.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000003-0000-0000-0000-000000000016', 'Pasta Carbonara', 'Italian', 'Medium', 10, 20, 4, '[{"instruction": "Bring a large pot of heavily salted water to boil. Cook 400g spaghetti until al dente. Reserve 1 cup pasta water before draining.", "step_number": 1, "time_minutes": 12}, {"instruction": "Whisk together 4 egg yolks, 2 whole eggs and 80g finely grated Pecorino Romano. Season with black pepper. Do not add salt yet.", "step_number": 2, "time_minutes": 5}, {"instruction": "Fry 150g guanciale (or pancetta) in a dry pan until fat renders and meat is crispy. Remove and set aside. Keep the rendered fat.", "step_number": 3, "time_minutes": 8}, {"instruction": "Off the heat, add the hot drained pasta to the guanciale fat and toss.", "step_number": 4, "time_minutes": 1}, {"instruction": "Immediately pour egg mixture over pasta and toss rapidly, adding reserved pasta water splash by splash to create a creamy sauce. The residual heat cooks the eggs — never let them scramble.", "step_number": 5, "time_minutes": 3}, {"instruction": "Fold in guanciale, adjust seasoning, and serve immediately with extra Pecorino and black pepper.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000003-0000-0000-0000-000000000017', 'Margherita Pizza', 'Italian', 'Hard', 120, 15, 4, '[{"instruction": "Dough: dissolve yeast in warm water with a pinch of sugar. Mix into flour with salt and olive oil. Knead 10 minutes. Rise 1–2 hours.", "step_number": 1, "time_minutes": 120}, {"instruction": "Preheat oven to maximum (250–280°C / 480–540°F) with a pizza stone or heavy baking sheet inside for at least 30 minutes.", "step_number": 2, "time_minutes": 30}, {"instruction": "Crush san Marzano tomatoes by hand with salt, olive oil and a pinch of sugar. This is the sauce — no cooking needed.", "step_number": 3, "time_minutes": 5}, {"instruction": "Stretch dough on a floured surface into a thin 12-inch round. Transfer to a peel or parchment.", "step_number": 4, "time_minutes": 5}, {"instruction": "Spread sauce thinly to 1cm from edge. Tear fresh mozzarella over. Drizzle olive oil. Slide onto hot stone.", "step_number": 5, "time_minutes": 5}, {"instruction": "Bake 8–12 minutes until crust is leopard-spotted and cheese is bubbling. Top with fresh basil after removing from oven.", "step_number": 6, "time_minutes": 12}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000003-0000-0000-0000-000000000018', 'Mushroom Risotto', 'Italian', 'Medium', 15, 35, 4, '[{"instruction": "Soak 20g dried porcini mushrooms in 250ml warm water for 30 minutes. Strain, reserving liquid. Roughly chop.", "step_number": 1, "time_minutes": 30}, {"instruction": "Heat 1 litre chicken or vegetable stock in a saucepan. Keep warm throughout cooking.", "step_number": 2, "time_minutes": 5}, {"instruction": "In a wide pan, soften diced shallots and garlic in butter and olive oil. Add 400g sliced fresh mushrooms and cook until golden.", "step_number": 3, "time_minutes": 10}, {"instruction": "Add 350g Arborio or Carnaroli rice. Toast for 2 minutes, stirring constantly. Add white wine and let absorb.", "step_number": 4, "time_minutes": 5}, {"instruction": "Add warm stock one ladle at a time, stirring after each addition until absorbed. Repeat for 20–22 minutes until rice is creamy and al dente.", "step_number": 5, "time_minutes": 22}, {"instruction": "Off heat, stir in cold butter and grated Parmigiano. Rest 2 minutes. Season and serve immediately.", "step_number": 6, "time_minutes": 3}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('b0000004-0000-0000-0000-000000000001', 'Carne Asada Tacos', 'Mexican', 'Easy', 30, 10, 4, '[{"instruction": "Marinate skirt steak in lime, garlic, cumin, chili.", "step_number": 1}, {"instruction": "Grill steak to medium-rare; rest 5 minutes.", "step_number": 2, "time_minutes": 8}, {"instruction": "Slice thin against the grain.", "step_number": 3}, {"instruction": "Serve in warm corn tortillas with onion, cilantro, lime.", "step_number": 4}]', 'https://images.example.com/tacos.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('a0000003-0000-0000-0000-000000000019', 'Beef Lasagna', 'Italian', 'Hard', 30, 90, 8, '[{"instruction": "Bolognese: fry diced onion, carrot and celery in olive oil. Brown ground beef. Add wine, tomatoes, stock and herbs. Simmer 45 minutes.", "step_number": 1, "time_minutes": 60}, {"instruction": "Béchamel: melt butter, whisk in flour, gradually add warm milk. Cook 5 minutes until thickened. Season with nutmeg and salt.", "step_number": 2, "time_minutes": 10}, {"instruction": "Cook lasagna sheets in salted water until barely al dente. Pat dry.", "step_number": 3, "time_minutes": 10}, {"instruction": "Build layers in a greased 33x23cm dish: Bolognese → pasta sheets → Béchamel → Parmigiano. Repeat 4 times.", "step_number": 4, "time_minutes": 15}, {"instruction": "Top with remaining Béchamel and a generous layer of Parmigiano. Cover with foil.", "step_number": 5, "time_minutes": 5}, {"instruction": "Bake at 180°C for 45 minutes. Remove foil and bake another 15 minutes until golden and bubbling. Rest 15 minutes before cutting.", "step_number": 6, "time_minutes": 60}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000003-0000-0000-0000-000000000020', 'Tiramisu', 'Italian', 'Medium', 30, 0, 8, '[{"instruction": "Separate 6 eggs. Beat yolks with 150g caster sugar until pale and doubled in volume.", "step_number": 1, "time_minutes": 8}, {"instruction": "Fold 500g mascarpone into the yolk mixture until smooth.", "step_number": 2, "time_minutes": 5}, {"instruction": "Whisk egg whites to stiff peaks. Gently fold into mascarpone mixture in three additions.", "step_number": 3, "time_minutes": 7}, {"instruction": "Make strong espresso (300ml). Cool slightly and add Marsala wine or rum (optional).", "step_number": 4, "time_minutes": 5}, {"instruction": "Dip Savoiardi biscuits briefly (1 second per side) in coffee. Lay in a single layer in a 25x18cm dish.", "step_number": 5, "time_minutes": 5}, {"instruction": "Spread half the mascarpone cream over. Repeat layer of soaked biscuits and remaining cream. Dust generously with cocoa powder. Refrigerate at least 4 hours before serving.", "step_number": 6, "time_minutes": 10}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000004-0000-0000-0000-000000000021', 'Street Tacos', 'Mexican', 'Easy', 15, 15, 4, '[{"instruction": "Marinate beef strips or chicken in lime juice, cumin, chilli powder, garlic and salt for 15 minutes.", "step_number": 1, "time_minutes": 15}, {"instruction": "Heat a griddle or cast-iron pan on high. Cook meat in batches until charred at edges. Chop finely.", "step_number": 2, "time_minutes": 10}, {"instruction": "Warm small corn tortillas directly over a gas flame or in a dry pan until pliable and slightly charred.", "step_number": 3, "time_minutes": 3}, {"instruction": "Prepare toppings: finely diced white onion, chopped coriander, halved limes, salsa verde and thinly sliced radishes.", "step_number": 4, "time_minutes": 5}, {"instruction": "Double up two tortillas per taco (authentic style). Fill with meat and top generously.", "step_number": 5, "time_minutes": 2}, {"instruction": "Squeeze fresh lime juice over each taco. Serve immediately with salsa and pickled jalapeños.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000004-0000-0000-0000-000000000022', 'Chicken Burrito', 'Mexican', 'Easy', 20, 20, 4, '[{"instruction": "Season chicken with fajita spice mix. Pan-fry until cooked through and slightly browned. Rest 5 minutes, then slice.", "step_number": 1, "time_minutes": 15}, {"instruction": "Cook cilantro-lime rice: rinse basmati, cook with chicken stock. When done, stir in lime zest, lime juice and chopped coriander.", "step_number": 2, "time_minutes": 20}, {"instruction": "Warm black beans (canned) in a small pan with cumin and pinch of salt.", "step_number": 3, "time_minutes": 5}, {"instruction": "Prepare fixings: sour cream, guacamole, shredded cheddar, salsa and iceberg lettuce.", "step_number": 4, "time_minutes": 5}, {"instruction": "Warm large flour tortillas in a dry pan. Arrange rice, beans, chicken and fixings in a horizontal line in the centre.", "step_number": 5, "time_minutes": 3}, {"instruction": "Fold sides in, then roll tightly from the bottom, tucking firmly. Optionally toast seam-side down on the pan for 1 minute.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000004-0000-0000-0000-000000000023', 'Cheese Enchiladas', 'Mexican', 'Medium', 20, 30, 4, '[{"instruction": "Make red enchilada sauce: toast dried guajillo and ancho chillies. Blend with onion, garlic, cumin, oregano and chicken stock until smooth. Simmer 10 minutes.", "step_number": 1, "time_minutes": 20}, {"instruction": "Warm corn tortillas briefly in a dry pan to make pliable.", "step_number": 2, "time_minutes": 5}, {"instruction": "Lightly coat each tortilla in sauce. Fill with a mix of shredded cheese (Monterey Jack + cheddar) and diced white onion. Roll tightly.", "step_number": 3, "time_minutes": 10}, {"instruction": "Arrange seam-side down in a greased baking dish. Pour remaining sauce over, ensuring all tortillas are covered.", "step_number": 4, "time_minutes": 5}, {"instruction": "Sprinkle remaining cheese generously over top.", "step_number": 5, "time_minutes": 2}, {"instruction": "Bake uncovered at 180°C for 20–25 minutes until cheese is bubbling. Garnish with sour cream, coriander and pickled jalapeños.", "step_number": 6, "time_minutes": 25}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000004-0000-0000-0000-000000000024', 'Classic Guacamole', 'Mexican', 'Easy', 10, 0, 4, '[{"instruction": "Choose ripe Hass avocados — they should yield to gentle pressure. Halve, remove stone and scoop flesh into a molcajete or bowl.", "step_number": 1, "time_minutes": 3}, {"instruction": "Mash avocado to your preferred texture (chunky or smooth) with a fork or pestle.", "step_number": 2, "time_minutes": 2}, {"instruction": "Finely dice half a white onion. Chop 1–2 jalapeño chillies (seeds removed for less heat). Add to avocado.", "step_number": 3, "time_minutes": 3}, {"instruction": "Add finely chopped fresh coriander (a generous handful), juice of 1 large lime and salt to taste.", "step_number": 4, "time_minutes": 1}, {"instruction": "Taste and adjust: more lime, salt or chilli as needed. Guacamole should be bright and acidic.", "step_number": 5, "time_minutes": 1}, {"instruction": "Serve immediately. If making ahead, press cling film directly onto the surface to prevent browning.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('b0000004-0000-0000-0000-000000000002', 'Bean and Cheese Burrito', 'Mexican', 'Easy', 10, 15, 4, '[{"instruction": "Warm refried beans with cumin and a splash of stock.", "step_number": 1}, {"instruction": "Toast tortilla briefly to soften.", "step_number": 2}, {"instruction": "Fill with beans, rice, cheese, salsa; fold and roll tight.", "step_number": 3}, {"instruction": "Sear seam-side down in a dry skillet to crisp.", "step_number": 4}]', 'https://images.example.com/burrito.jpg', false, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('a0000004-0000-0000-0000-000000000025', 'Quesadillas', 'Mexican', 'Easy', 10, 10, 4, '[{"instruction": "Prepare filling: cook sliced chicken or vegetables with onion, peppers and fajita seasoning until soft and lightly charred.", "step_number": 1, "time_minutes": 8}, {"instruction": "Shred or cube cheese: use Oaxacan cheese, Monterey Jack or mozzarella for best melt.", "step_number": 2, "time_minutes": 2}, {"instruction": "Heat a large non-stick pan on medium. Place a flour tortilla flat. Spread filling on half, then cheese.", "step_number": 3, "time_minutes": 2}, {"instruction": "Fold tortilla in half. Press gently with spatula. Cook 2–3 minutes until golden on the bottom.", "step_number": 4, "time_minutes": 3}, {"instruction": "Flip and cook another 2 minutes until cheese is fully melted and second side is golden.", "step_number": 5, "time_minutes": 2}, {"instruction": "Cut into wedges. Serve with sour cream, guacamole and fresh salsa.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000005-0000-0000-0000-000000000026', 'Pad Thai', 'Thai', 'Medium', 20, 15, 4, '[{"instruction": "Soak 200g flat rice noodles in room-temperature water for 30 minutes. They should be pliable but still firm.", "step_number": 1, "time_minutes": 30}, {"instruction": "Pad Thai sauce: mix tamarind paste, fish sauce, palm sugar and sriracha. Adjust for sweet-sour-salty balance.", "step_number": 2, "time_minutes": 5}, {"instruction": "Heat wok on very high heat. Stir-fry 200g prawns or tofu cubes in oil until just cooked. Set aside.", "step_number": 3, "time_minutes": 4}, {"instruction": "In the same wok, scramble 2 eggs lightly. Add drained noodles and sauce. Toss vigorously.", "step_number": 4, "time_minutes": 4}, {"instruction": "Add prawns/tofu, bean sprouts and sliced spring onions. Toss 1 minute.", "step_number": 5, "time_minutes": 2}, {"instruction": "Plate and serve with crushed peanuts, lime wedge, chilli flakes and dried shrimp on the side.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000005-0000-0000-0000-000000000027', 'Thai Green Curry', 'Thai', 'Medium', 15, 25, 4, '[{"instruction": "Heat 1 tbsp oil in a wok. Fry 2–3 tbsp green curry paste for 1–2 minutes until fragrant.", "step_number": 1, "time_minutes": 3}, {"instruction": "Add 400ml thick coconut milk. Stir well and bring to a simmer.", "step_number": 2, "time_minutes": 5}, {"instruction": "Add 400g sliced chicken breast or tofu. Cook on medium heat for 10 minutes.", "step_number": 3, "time_minutes": 10}, {"instruction": "Add vegetables: Thai eggplant, courgette, baby corn and red bell pepper. Simmer 5 minutes.", "step_number": 4, "time_minutes": 5}, {"instruction": "Season with fish sauce, palm sugar and lime leaves. Taste and balance.", "step_number": 5, "time_minutes": 3}, {"instruction": "Finish with Thai basil leaves and sliced red chilli. Serve with jasmine rice.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000005-0000-0000-0000-000000000028', 'Tom Yum Soup', 'Thai', 'Easy', 10, 20, 4, '[{"instruction": "Bring 1 litre chicken or shrimp stock to a boil. Add bruised lemongrass stalks, galangal slices, kaffir lime leaves and dried chillies. Simmer 10 minutes to infuse.", "step_number": 1, "time_minutes": 10}, {"instruction": "Add halved mushrooms (shiitake or oyster) and cherry tomatoes to the broth.", "step_number": 2, "time_minutes": 5}, {"instruction": "Add 300g prawns (shell-on for more flavour). Cook until pink, 2–3 minutes.", "step_number": 3, "time_minutes": 3}, {"instruction": "Season with fish sauce and lime juice. Taste — it should be intensely sour, savoury and spicy.", "step_number": 4, "time_minutes": 2}, {"instruction": "Ladle into bowls. Garnish with fresh coriander and a squeeze of lime.", "step_number": 5, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000005-0000-0000-0000-000000000029', 'Fresh Spring Rolls', 'Thai', 'Easy', 30, 0, 4, '[{"instruction": "Prep all fillings: cook vermicelli noodles, cool in cold water; poach prawns until pink, halve lengthways; shred lettuce; julienne carrot and cucumber; pick coriander and mint.", "step_number": 1, "time_minutes": 20}, {"instruction": "Lay out all components in bowls ready for assembly line rolling.", "step_number": 2, "time_minutes": 5}, {"instruction": "Fill a wide bowl with warm water. Dip one rice paper sheet for 10–15 seconds until just pliable (it will continue softening).", "step_number": 3, "time_minutes": 1}, {"instruction": "Lay flat on a damp surface. Place a few herb leaves on the lower third (they will show through). Layer noodles, carrot, cucumber, lettuce and prawns (pink-side down) on top.", "step_number": 4, "time_minutes": 2}, {"instruction": "Fold the sides in, then roll from the bottom up firmly, tucking as you go.", "step_number": 5, "time_minutes": 2}, {"instruction": "Serve immediately with peanut dipping sauce or sweet chilli sauce.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('a0000005-0000-0000-0000-000000000030', 'Mango Sticky Rice', 'Thai', 'Easy', 120, 30, 4, '[{"instruction": "Soak 400g Thai glutinous rice in cold water for 2 hours. Drain well.", "step_number": 1, "time_minutes": 120}, {"instruction": "Steam drained rice in a bamboo or metal steamer for 25–30 minutes until translucent and cooked through.", "step_number": 2, "time_minutes": 30}, {"instruction": "While rice steams, warm 400ml coconut milk with 80g sugar and 1 tsp salt, stirring until dissolved. Do not boil.", "step_number": 3, "time_minutes": 5}, {"instruction": "Pour 2/3 of the warm coconut milk over hot cooked rice. Stir gently. Cover and rest 20 minutes — rice will absorb the milk.", "step_number": 4, "time_minutes": 20}, {"instruction": "Peel and slice 4 ripe mangoes. Arrange beside a mound of coconut-infused sticky rice.", "step_number": 5, "time_minutes": 5}, {"instruction": "Drizzle remaining coconut sauce over rice and mango. Garnish with toasted sesame seeds and a pandan leaf.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.468719+00', NULL, NULL, NULL, NULL),
	('b1000000-0000-0000-0000-000000000001', 'Chicken Manchurian', 'Indo-Chinese', 'Medium', 15, 20, 4, '[{"instruction": "Cut chicken into bite-sized cubes. Marinate with soy sauce, ginger-garlic paste, salt and pepper for 15 minutes.", "step_number": 1, "time_minutes": 15}, {"instruction": "Coat chicken in a batter of cornflour, all-purpose flour, egg and water. Deep-fry until golden brown and crisp.", "step_number": 2, "time_minutes": 8}, {"instruction": "In a wok heat 2 tbsp oil. Stir-fry chopped garlic, ginger and green chilli for 30 seconds.", "step_number": 3, "time_minutes": 2}, {"instruction": "Add diced onions and capsicum, toss on high heat for 2 minutes.", "step_number": 4, "time_minutes": 2}, {"instruction": "Pour in soy sauce, vinegar, tomato ketchup and chilli sauce. Add 1/2 cup water with 1 tsp cornflour slurry.", "step_number": 5, "time_minutes": 3}, {"instruction": "When sauce thickens, toss the fried chicken in. Garnish with spring onion greens.", "step_number": 6, "time_minutes": 3}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b1000000-0000-0000-0000-000000000002', 'Hakka Noodles', 'Indo-Chinese', 'Easy', 10, 15, 3, '[{"instruction": "Boil noodles in salted water with 1 tsp oil until just tender. Drain, rinse under cold water and toss with 1 tsp oil.", "step_number": 1, "time_minutes": 8}, {"instruction": "Heat 2 tbsp oil in a wok on high heat. Add minced garlic and ginger, stir for 20 seconds.", "step_number": 2, "time_minutes": 1}, {"instruction": "Add julienned carrots, cabbage, capsicum and spring onion whites. Stir-fry on highest heat for 2 minutes.", "step_number": 3, "time_minutes": 2}, {"instruction": "Add soy sauce, vinegar, white pepper and salt. Toss the noodles in.", "step_number": 4, "time_minutes": 2}, {"instruction": "Stir-fry on high heat for 2 more minutes lifting noodles from below to coat evenly.", "step_number": 5, "time_minutes": 2}, {"instruction": "Garnish with spring onion greens and serve immediately.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b1000000-0000-0000-0000-000000000003', 'Gobi Manchurian', 'Indo-Chinese', 'Medium', 15, 20, 4, '[{"instruction": "Break cauliflower into small florets and blanch in hot salted water for 3 minutes. Drain well.", "step_number": 1, "time_minutes": 5}, {"instruction": "Make batter from cornflour, all-purpose flour, ginger-garlic paste, salt, soy sauce and water.", "step_number": 2, "time_minutes": 3}, {"instruction": "Coat florets in batter and deep-fry in hot oil until crisp and golden.", "step_number": 3, "time_minutes": 8}, {"instruction": "In a wok heat 2 tbsp oil. Stir-fry chopped garlic, ginger and green chilli for 30 seconds.", "step_number": 4, "time_minutes": 1}, {"instruction": "Add chopped onion and capsicum. Toss for 2 minutes. Add soy sauce, chilli sauce, vinegar and tomato ketchup.", "step_number": 5, "time_minutes": 3}, {"instruction": "Thicken with cornflour slurry. Toss fried cauliflower in sauce. Garnish with spring onions.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b1000000-0000-0000-0000-000000000004', 'Schezwan Fried Rice', 'Indo-Chinese', 'Easy', 10, 12, 3, '[{"instruction": "Use cold cooked basmati rice (1 day old works best). Spread on a plate to dry.", "step_number": 1, "time_minutes": 2}, {"instruction": "Heat 2 tbsp oil in a wok on high heat. Add minced garlic and ginger; stir-fry 30 seconds.", "step_number": 2, "time_minutes": 1}, {"instruction": "Add diced carrots, beans, capsicum and spring onion whites. Stir-fry on high for 2 minutes.", "step_number": 3, "time_minutes": 2}, {"instruction": "Add 2 tbsp Schezwan sauce, 1 tbsp soy sauce and salt. Toss for 1 minute.", "step_number": 4, "time_minutes": 1}, {"instruction": "Add the cooked rice. Toss continuously on highest flame for 3-4 minutes until the rice is hot and coated.", "step_number": 5, "time_minutes": 4}, {"instruction": "Garnish with spring onion greens. Serve hot.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b1000000-0000-0000-0000-000000000005', 'Chilli Paneer', 'Indo-Chinese', 'Easy', 10, 15, 3, '[{"instruction": "Cube 250g paneer. Toss with 2 tbsp cornflour, 1 tbsp all-purpose flour, salt, pepper and 1 tsp soy sauce.", "step_number": 1, "time_minutes": 3}, {"instruction": "Shallow-fry coated paneer in hot oil for 2-3 minutes until lightly golden. Drain.", "step_number": 2, "time_minutes": 5}, {"instruction": "In the same pan, leave 2 tbsp oil. Add minced garlic, ginger and slit green chillies; stir for 30 seconds.", "step_number": 3, "time_minutes": 1}, {"instruction": "Add cubed onion and capsicum, toss on high heat 2 minutes.", "step_number": 4, "time_minutes": 2}, {"instruction": "Add soy sauce, chilli sauce, tomato ketchup, vinegar and 1/4 cup water. Bring to a boil.", "step_number": 5, "time_minutes": 2}, {"instruction": "Thicken with cornflour slurry. Toss paneer in sauce, garnish with spring onions.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b2000000-0000-0000-0000-000000000001', 'Chicken Teriyaki', 'Japanese', 'Easy', 10, 15, 2, '[{"instruction": "Pat dry boneless chicken thighs. Season lightly with salt and pepper.", "step_number": 1, "time_minutes": 2}, {"instruction": "Mix 3 tbsp soy sauce, 3 tbsp mirin, 2 tbsp sake and 1 tbsp sugar in a bowl to make teriyaki sauce.", "step_number": 2, "time_minutes": 2}, {"instruction": "Heat 1 tbsp oil in a non-stick pan. Place chicken skin-side down and cook on medium-high heat for 5 minutes.", "step_number": 3, "time_minutes": 5}, {"instruction": "Flip and cook the other side 4 minutes. Drain excess fat.", "step_number": 4, "time_minutes": 4}, {"instruction": "Pour in teriyaki sauce. Spoon the sauce over the chicken and reduce heat to simmer for 2-3 minutes until glossy.", "step_number": 5, "time_minutes": 3}, {"instruction": "Slice and serve over steamed rice with sesame seeds and spring onion.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b2000000-0000-0000-0000-000000000002', 'Miso Soup', 'Japanese', 'Easy', 5, 10, 2, '[{"instruction": "Soak 1 small piece of kombu in 3 cups water for 15 minutes (or use instant dashi).", "step_number": 1, "time_minutes": 15}, {"instruction": "Bring to a near-boil and remove kombu. Add bonito flakes, simmer 30 seconds, then strain to make dashi.", "step_number": 2, "time_minutes": 3}, {"instruction": "Cube silken tofu and slice spring onion thinly.", "step_number": 3, "time_minutes": 2}, {"instruction": "Lower heat. Whisk 2 tbsp white miso paste with a ladle of dashi until smooth, then return to pot.", "step_number": 4, "time_minutes": 1}, {"instruction": "Add tofu and rehydrated wakame seaweed. Heat through but do not boil (boiling damages miso flavour).", "step_number": 5, "time_minutes": 2}, {"instruction": "Garnish with spring onion. Serve immediately.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b2000000-0000-0000-0000-000000000003', 'Chicken Katsu', 'Japanese', 'Medium', 15, 15, 2, '[{"instruction": "Butterfly 2 chicken breasts and pound to 1cm thickness. Season with salt and pepper.", "step_number": 1, "time_minutes": 3}, {"instruction": "Set up a breading station: flour, beaten egg and panko breadcrumbs in three plates.", "step_number": 2, "time_minutes": 2}, {"instruction": "Coat chicken in flour, dip in egg, then press into panko to coat thoroughly.", "step_number": 3, "time_minutes": 3}, {"instruction": "Heat 1 inch of vegetable oil in a deep pan to 170°C (340°F).", "step_number": 4, "time_minutes": 4}, {"instruction": "Fry chicken 3-4 minutes per side until deep golden brown. Drain on a wire rack.", "step_number": 5, "time_minutes": 7}, {"instruction": "Slice across the grain. Serve with shredded cabbage, rice and tonkatsu sauce.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b2000000-0000-0000-0000-000000000004', 'Salmon Sushi Bowl', 'Japanese', 'Easy', 15, 10, 2, '[{"instruction": "Cook 1 cup sushi rice per package. Stir in 2 tbsp rice vinegar, 1 tbsp sugar and 1 tsp salt while warm.", "step_number": 1, "time_minutes": 18}, {"instruction": "Cube 200g sashimi-grade salmon. Toss with 1 tbsp soy sauce, 1 tsp sesame oil and 1/2 tsp grated ginger.", "step_number": 2, "time_minutes": 5}, {"instruction": "Slice avocado, julienne carrot and cucumber. Edamame can be steamed or used frozen-thawed.", "step_number": 3, "time_minutes": 5}, {"instruction": "Divide warm rice into bowls. Arrange salmon and vegetables in sections on top.", "step_number": 4, "time_minutes": 2}, {"instruction": "Drizzle with soy sauce and sriracha mayo (1 tbsp mayo + 1 tsp sriracha).", "step_number": 5, "time_minutes": 1}, {"instruction": "Top with sesame seeds, nori strips and pickled ginger. Serve immediately.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b2000000-0000-0000-0000-000000000005', 'Vegetable Ramen', 'Japanese', 'Medium', 10, 25, 2, '[{"instruction": "Make broth: simmer 4 cups vegetable stock with 1 piece kombu, 4 dried shiitake, 2 garlic cloves, 1-inch ginger for 15 minutes.", "step_number": 1, "time_minutes": 15}, {"instruction": "Strain. Stir in 2 tbsp white miso, 2 tbsp soy sauce and 1 tsp sesame oil. Keep warm.", "step_number": 2, "time_minutes": 2}, {"instruction": "Cook ramen noodles per package directions, drain and rinse.", "step_number": 3, "time_minutes": 4}, {"instruction": "Soft-boil 2 eggs (6.5 minutes), peel and halve.", "step_number": 4, "time_minutes": 7}, {"instruction": "Sauté pak choi or spinach in 1 tsp oil for 1 minute. Slice mushrooms and corn.", "step_number": 5, "time_minutes": 2}, {"instruction": "Divide noodles in bowls. Pour hot broth over. Top with eggs, vegetables, nori and spring onion.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b3000000-0000-0000-0000-000000000001', 'Hummus', 'Mediterranean', 'Easy', 10, 0, 4, '[{"instruction": "Drain 1 can chickpeas, reserving liquid (aquafaba). For ultra-smooth hummus, peel chickpea skins (optional).", "step_number": 1, "time_minutes": 3}, {"instruction": "In a food processor, blend 1/3 cup tahini and juice of 1 lemon for 1 minute until creamy and lighter in colour.", "step_number": 2, "time_minutes": 2}, {"instruction": "Add 2 garlic cloves, 1/2 tsp ground cumin and 1/2 tsp salt. Pulse to combine.", "step_number": 3, "time_minutes": 1}, {"instruction": "Add chickpeas in two batches, blending each batch for 1 minute. Scrape sides between additions.", "step_number": 4, "time_minutes": 3}, {"instruction": "With motor running, drizzle in 2-3 tbsp ice water (or aquafaba) until silky smooth.", "step_number": 5, "time_minutes": 1}, {"instruction": "Transfer to a bowl. Make a well in the centre and drizzle with olive oil. Top with paprika and parsley.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b3000000-0000-0000-0000-000000000002', 'Greek Salad', 'Mediterranean', 'Easy', 10, 0, 4, '[{"instruction": "Cut 4 ripe tomatoes into chunks. Slice 1 cucumber into half-moons.", "step_number": 1, "time_minutes": 3}, {"instruction": "Cut 1 red onion into thin slices. Soak briefly in cold water to mellow the bite.", "step_number": 2, "time_minutes": 3}, {"instruction": "Slice 1 green capsicum into rings. Pit 1/2 cup Kalamata olives if not already pitted.", "step_number": 3, "time_minutes": 2}, {"instruction": "In a wide bowl, combine tomatoes, cucumber, onion, capsicum and olives.", "step_number": 4, "time_minutes": 1}, {"instruction": "Drizzle with 3 tbsp extra-virgin olive oil and 1 tbsp red wine vinegar. Sprinkle with 1 tsp dried oregano and salt.", "step_number": 5, "time_minutes": 1}, {"instruction": "Top with a thick slab (200g) of feta cheese, crack black pepper. Do not toss — serve as is.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b3000000-0000-0000-0000-000000000003', 'Falafel', 'Mediterranean', 'Medium', 480, 15, 4, '[{"instruction": "Soak 1 cup dried chickpeas in cold water overnight (do not use canned).", "step_number": 1, "time_minutes": 480}, {"instruction": "Drain. In a food processor blitz chickpeas with onion, garlic, parsley, coriander, cumin, coriander powder, salt and 1 tsp baking powder until coarse but cohesive.", "step_number": 2, "time_minutes": 3}, {"instruction": "Refrigerate the mixture for 30 minutes (helps balls hold).", "step_number": 3, "time_minutes": 30}, {"instruction": "Shape into walnut-sized balls or patties (use a falafel scoop or two spoons).", "step_number": 4, "time_minutes": 5}, {"instruction": "Deep-fry in 170°C (340°F) oil in batches for 4-5 minutes until deep brown.", "step_number": 5, "time_minutes": 10}, {"instruction": "Drain. Serve in pita with tahini sauce, tomato, cucumber and pickled turnips.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b3000000-0000-0000-0000-000000000004', 'Shakshuka', 'Mediterranean', 'Easy', 5, 25, 4, '[{"instruction": "Heat 2 tbsp olive oil in a wide skillet. Sauté 1 sliced onion until softened (5 min).", "step_number": 1, "time_minutes": 5}, {"instruction": "Add 1 sliced red capsicum and cook 5 more minutes until tender.", "step_number": 2, "time_minutes": 5}, {"instruction": "Stir in 3 minced garlic cloves, 1 tsp paprika, 1 tsp cumin, 1/2 tsp chilli flakes. Cook 30 seconds.", "step_number": 3, "time_minutes": 1}, {"instruction": "Add 1 can (400g) crushed tomatoes, salt and a pinch of sugar. Simmer 8-10 minutes until thickened.", "step_number": 4, "time_minutes": 10}, {"instruction": "Make 4 wells in the sauce. Crack 1 egg into each. Cover and cook 5-7 minutes until whites are set but yolks runny.", "step_number": 5, "time_minutes": 7}, {"instruction": "Sprinkle with chopped parsley and crumbled feta. Serve with crusty bread.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b3000000-0000-0000-0000-000000000005', 'Tabbouleh', 'Mediterranean', 'Easy', 20, 0, 4, '[{"instruction": "Soak 1/2 cup fine bulgur in 1/2 cup boiling water for 15 minutes. Drain and squeeze dry.", "step_number": 1, "time_minutes": 15}, {"instruction": "Finely chop 2 large bunches flat-leaf parsley (about 4 cups). The chop should be very fine — almost like minced.", "step_number": 2, "time_minutes": 8}, {"instruction": "Finely chop 1 small bunch fresh mint and 4 spring onions.", "step_number": 3, "time_minutes": 3}, {"instruction": "Dice 3 ripe tomatoes very small (5mm). Drain off excess juice in a sieve.", "step_number": 4, "time_minutes": 3}, {"instruction": "Make dressing: whisk 1/3 cup lemon juice, 1/3 cup olive oil, 1 tsp salt, 1/4 tsp allspice and freshly cracked pepper.", "step_number": 5, "time_minutes": 2}, {"instruction": "Combine all ingredients in a bowl. Toss gently. Rest 10 minutes before serving for flavours to meld.", "step_number": 6, "time_minutes": 10}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL);
INSERT INTO public.recipes VALUES
	('b4000000-0000-0000-0000-000000000001', 'Rajma Chawal', 'Indian', 'Medium', 480, 45, 4, '[{"instruction": "Soak 1 cup kidney beans (rajma) in cold water overnight.", "step_number": 1, "time_minutes": 480}, {"instruction": "Pressure cook soaked rajma with salt and water for 25 minutes (or until very tender).", "step_number": 2, "time_minutes": 25}, {"instruction": "Heat 2 tbsp ghee. Sauté finely chopped onion until deep golden. Add ginger-garlic paste.", "step_number": 3, "time_minutes": 8}, {"instruction": "Add chopped tomato, all spices (coriander, cumin, garam masala, chilli powder, turmeric). Cook until oil separates.", "step_number": 4, "time_minutes": 8}, {"instruction": "Add cooked rajma with its liquid. Simmer 15 minutes mashing some beans against the pot to thicken the gravy.", "step_number": 5, "time_minutes": 15}, {"instruction": "Adjust salt. Garnish with fresh coriander. Serve with steamed basmati rice.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b4000000-0000-0000-0000-000000000002', 'Masala Dosa', 'Indian', 'Hard', 720, 25, 4, '[{"instruction": "Soak 2 cups parboiled rice and 1/2 cup urad dal separately in water for 6 hours.", "step_number": 1, "time_minutes": 360}, {"instruction": "Grind separately to a smooth batter. Mix together with salt. Ferment overnight (8-12 hours).", "step_number": 2, "time_minutes": 480}, {"instruction": "For aloo masala: boil 4 potatoes, mash coarsely. Temper mustard seeds, urad dal, curry leaves and chillies in oil.", "step_number": 3, "time_minutes": 15}, {"instruction": "Add chopped onion, ginger, turmeric and salt. Cook 5 minutes. Add mashed potato, peas, fresh coriander.", "step_number": 4, "time_minutes": 8}, {"instruction": "Heat a flat tawa. Pour a ladle of batter and spread thin in a spiral motion. Drizzle ghee on edges.", "step_number": 5, "time_minutes": 2}, {"instruction": "When edges crisp up and bottom is golden (2 min), spoon potato filling, fold dosa over and serve with chutney and sambar.", "step_number": 6, "time_minutes": 3}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b5000000-0000-0000-0000-000000000001', 'Mapo Tofu', 'Chinese', 'Medium', 10, 15, 3, '[{"instruction": "Cube 400g silken tofu. Slip into a pot of warm salted water and keep warm — this firms tofu without breaking.", "step_number": 1, "time_minutes": 3}, {"instruction": "Heat 2 tbsp oil in a wok. Brown 200g minced pork or beef on high heat for 3 minutes.", "step_number": 2, "time_minutes": 3}, {"instruction": "Push to side. Add 2 tbsp doubanjiang (chilli bean paste) and 1 tbsp fermented black beans; fry 1 minute until oil reddens.", "step_number": 3, "time_minutes": 1}, {"instruction": "Add minced garlic and ginger, stir 30 seconds. Pour in 1 cup chicken stock, 1 tbsp soy sauce and 1 tsp sugar.", "step_number": 4, "time_minutes": 2}, {"instruction": "Drain tofu and gently slide into the sauce. Simmer 4 minutes — do not stir vigorously, push tofu around with the back of a spoon.", "step_number": 5, "time_minutes": 5}, {"instruction": "Thicken with cornflour slurry. Garnish with spring onion and 1/2 tsp ground Sichuan peppercorn for the famous tongue-tingling kick.", "step_number": 6, "time_minutes": 2}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b5000000-0000-0000-0000-000000000002', 'Beef and Broccoli', 'Chinese', 'Easy', 15, 10, 3, '[{"instruction": "Slice 400g flank steak across the grain into 5mm strips. Marinate in 1 tbsp soy sauce, 1 tsp cornflour and 1 tsp oil for 15 minutes.", "step_number": 1, "time_minutes": 15}, {"instruction": "Blanch 400g broccoli florets in salted boiling water for 90 seconds. Drain.", "step_number": 2, "time_minutes": 3}, {"instruction": "Mix sauce: 3 tbsp oyster sauce, 2 tbsp soy sauce, 1 tbsp shaoxing wine, 1 tsp sesame oil, 1 tsp sugar, 1 tsp cornflour, 1/3 cup water.", "step_number": 3, "time_minutes": 2}, {"instruction": "Heat 2 tbsp oil in a wok smoking hot. Sear beef in a single layer for 1 minute per side. Remove.", "step_number": 4, "time_minutes": 2}, {"instruction": "Add 1 tbsp oil, fry minced garlic and ginger 20 seconds. Add broccoli, toss 1 minute.", "step_number": 5, "time_minutes": 2}, {"instruction": "Return beef. Pour sauce, toss until thickened (1 minute). Serve over rice.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b6000000-0000-0000-0000-000000000001', 'Spaghetti Bolognese', 'Italian', 'Medium', 10, 90, 4, '[{"instruction": "Heat 2 tbsp olive oil and 30g butter in a heavy pan. Sauté finely diced onion, carrot and celery (soffritto) on low heat for 10 minutes until soft and sweet.", "step_number": 1, "time_minutes": 10}, {"instruction": "Increase heat. Add 500g minced beef (and 100g pancetta if available). Brown deeply for 8 minutes, breaking up clumps.", "step_number": 2, "time_minutes": 8}, {"instruction": "Pour in 1/2 cup white wine and let it bubble away for 2 minutes.", "step_number": 3, "time_minutes": 2}, {"instruction": "Add 400g crushed tomatoes, 1 tbsp tomato paste, 1 cup whole milk, salt, pepper, a pinch of nutmeg and a bay leaf.", "step_number": 4, "time_minutes": 3}, {"instruction": "Bring to a bare simmer. Cover partially and cook on lowest heat for 60-90 minutes, stirring occasionally. The sauce should be silky and rich.", "step_number": 5, "time_minutes": 75}, {"instruction": "Cook spaghetti to al dente. Toss with sauce off the heat. Top with grated Parmigiano-Reggiano.", "step_number": 6, "time_minutes": 12}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b6000000-0000-0000-0000-000000000002', 'Caprese Salad', 'Italian', 'Easy', 8, 0, 2, '[{"instruction": "Choose ripe heirloom tomatoes (about 400g). Slice into 1cm rounds.", "step_number": 1, "time_minutes": 3}, {"instruction": "Slice 250g fresh mozzarella di bufala into similar thickness.", "step_number": 2, "time_minutes": 2}, {"instruction": "On a serving platter, alternate tomato and mozzarella slices in a circular pattern.", "step_number": 3, "time_minutes": 2}, {"instruction": "Tuck whole fresh basil leaves between slices.", "step_number": 4, "time_minutes": 1}, {"instruction": "Drizzle generously with extra-virgin olive oil and a few drops of aged balsamic.", "step_number": 5, "time_minutes": 1}, {"instruction": "Finish with flaky sea salt and freshly cracked black pepper. Serve immediately at room temperature.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b0000004-0000-0000-0000-000000000003', 'Chicken Enchiladas Verdes', 'Mexican', 'Medium', 20, 30, 6, '[{"instruction": "Poach and shred chicken; toss with cheese.", "step_number": 1}, {"instruction": "Roast tomatillos, onion, jalapeño; blend for green sauce.", "step_number": 2}, {"instruction": "Roll filled tortillas, top with sauce and cheese.", "step_number": 3}, {"instruction": "Bake at 375°F until bubbling.", "step_number": 4, "time_minutes": 20}]', 'https://images.example.com/enchiladas.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b7000000-0000-0000-0000-000000000001', 'Chicken Fajitas', 'Mexican', 'Easy', 15, 15, 4, '[{"instruction": "Slice 600g chicken breast into 1cm strips. Marinate with 2 tbsp olive oil, lime juice, 1 tsp cumin, 1 tsp paprika, 1 tsp chilli powder, salt and pepper for 15 minutes.", "step_number": 1, "time_minutes": 15}, {"instruction": "Slice 2 capsicums (mixed colours) and 1 onion into thick strips.", "step_number": 2, "time_minutes": 3}, {"instruction": "Heat a cast-iron pan smoking hot. Sear chicken in a single layer 2-3 minutes per side. Remove.", "step_number": 3, "time_minutes": 6}, {"instruction": "In the same pan, char capsicum and onion 4 minutes leaving them with bite.", "step_number": 4, "time_minutes": 4}, {"instruction": "Return chicken to the pan. Toss together for 1 minute, squeeze with extra lime.", "step_number": 5, "time_minutes": 2}, {"instruction": "Warm flour tortillas. Fill with fajitas and serve with sour cream, salsa and guacamole.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b7000000-0000-0000-0000-000000000002', 'Pico de Gallo', 'Mexican', 'Easy', 10, 0, 4, '[{"instruction": "Dice 4 ripe tomatoes very small (5mm). Drain in a sieve to remove excess juice.", "step_number": 1, "time_minutes": 4}, {"instruction": "Finely dice 1/2 white onion. Soak briefly in cold water to remove sharp bite, then drain.", "step_number": 2, "time_minutes": 3}, {"instruction": "Mince 1 jalapeño (remove seeds for less heat).", "step_number": 3, "time_minutes": 1}, {"instruction": "Roughly chop 1/2 bunch fresh coriander.", "step_number": 4, "time_minutes": 1}, {"instruction": "Combine all in a bowl. Add juice of 2 limes and 1/2 tsp salt.", "step_number": 5, "time_minutes": 1}, {"instruction": "Toss gently. Rest 10 minutes for flavours to mingle. Serve with chips, tacos or grilled meat.", "step_number": 6, "time_minutes": 10}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b8000000-0000-0000-0000-000000000001', 'Tom Kha Gai', 'Thai', 'Easy', 10, 20, 4, '[{"instruction": "Slice 1-inch galangal into thin coins. Bruise 2 stalks lemongrass and cut into 2-inch pieces. Tear 5 kaffir lime leaves.", "step_number": 1, "time_minutes": 3}, {"instruction": "In a pot bring 2 cups chicken stock to a boil. Add galangal, lemongrass and lime leaves. Simmer 5 minutes for the aromatics to infuse.", "step_number": 2, "time_minutes": 5}, {"instruction": "Add 1 can (400ml) coconut milk. Bring back to a gentle simmer (do not boil hard).", "step_number": 3, "time_minutes": 3}, {"instruction": "Add 400g sliced chicken thigh and 200g sliced mushrooms. Cook 6 minutes until chicken is cooked through.", "step_number": 4, "time_minutes": 6}, {"instruction": "Off the heat, season with 2 tbsp fish sauce, 1 tbsp sugar, juice of 2 limes and 2-3 crushed Thai chillies to taste.", "step_number": 5, "time_minutes": 2}, {"instruction": "Garnish with fresh coriander leaves. Serve with steamed jasmine rice.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b8000000-0000-0000-0000-000000000002', 'Pad See Ew', 'Thai', 'Medium', 10, 12, 2, '[{"instruction": "Soak 200g wide rice noodles in warm water until pliable (or use fresh sen yai noodles).", "step_number": 1, "time_minutes": 15}, {"instruction": "Mix sauce: 2 tbsp dark soy sauce, 2 tbsp light soy sauce, 1 tbsp oyster sauce, 1 tbsp sugar, 1 tsp white pepper.", "step_number": 2, "time_minutes": 2}, {"instruction": "Heat 2 tbsp oil in a wok smoking hot. Add minced garlic, fry 10 seconds. Add 200g sliced chicken, stir-fry 2 minutes.", "step_number": 3, "time_minutes": 3}, {"instruction": "Push to side. Crack 2 eggs into the wok, scramble briefly. Add 200g Chinese broccoli (gai lan), toss 1 minute.", "step_number": 4, "time_minutes": 2}, {"instruction": "Add drained noodles and the sauce. Toss aggressively on highest heat for 2 minutes — you want some charred edges (wok hei).", "step_number": 5, "time_minutes": 2}, {"instruction": "Plate immediately. Serve with chilli vinegar (prik nam som) on the side.", "step_number": 6, "time_minutes": 1}]', NULL, false, '2026-05-15 00:55:41.857087+00', NULL, NULL, NULL, NULL),
	('b0000001-0000-0000-0000-000000000001', 'Dal Makhani', 'Indian', 'Medium', 480, 60, 6, '[{"instruction": "Soak black urad dal and rajma overnight.", "step_number": 1}, {"instruction": "Pressure cook dals until tender.", "step_number": 2}, {"instruction": "Simmer with tomato puree, butter, and cream for 45 minutes.", "step_number": 3, "time_minutes": 45}, {"instruction": "Finish with kasuri methi and a drizzle of cream.", "step_number": 4}]', 'https://images.example.com/dal-makhani.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000001-0000-0000-0000-000000000002', 'Samosa', 'Indian', 'Medium', 30, 25, 8, '[{"instruction": "Make dough with flour, oil, and water; rest 30 minutes.", "step_number": 1, "time_minutes": 30}, {"instruction": "Cook spiced potato-pea filling.", "step_number": 2}, {"instruction": "Fold dough cones, fill, and seal edges.", "step_number": 3}, {"instruction": "Deep fry at low heat until golden.", "step_number": 4, "time_minutes": 15}]', 'https://images.example.com/samosa.jpg', false, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000001-0000-0000-0000-000000000003', 'Naan', 'Indian', 'Easy', 90, 8, 4, '[{"instruction": "Mix flour, yogurt, yeast, sugar; knead and rest 1 hour.", "step_number": 1, "time_minutes": 60}, {"instruction": "Divide and stretch into oblong shapes.", "step_number": 2}, {"instruction": "Cook on hot tawa or under broiler until puffed and charred.", "step_number": 3, "time_minutes": 3}, {"instruction": "Brush with melted butter and cilantro.", "step_number": 4}]', 'https://images.example.com/naan.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000001-0000-0000-0000-000000000004', 'Paneer Tikka', 'Indian', 'Medium', 60, 15, 4, '[{"instruction": "Marinate paneer cubes in yogurt and spices for 45 minutes.", "step_number": 1, "time_minutes": 45}, {"instruction": "Skewer with onion and bell pepper.", "step_number": 2}, {"instruction": "Grill or broil until charred at the edges.", "step_number": 3, "time_minutes": 12}]', 'https://images.example.com/paneer-tikka.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000002-0000-0000-0000-000000000001', 'Pork Dumplings', 'Chinese', 'Medium', 45, 15, 6, '[{"instruction": "Mix ground pork, scallion, ginger, soy, sesame oil.", "step_number": 1}, {"instruction": "Wrap filling in dumpling skins, pleating one edge.", "step_number": 2}, {"instruction": "Pan-fry with water for steam-fry method.", "step_number": 3, "time_minutes": 12}]', 'https://images.example.com/dumplings.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000004-0000-0000-0000-000000000005', 'Cheese Quesadilla', 'Mexican', 'Easy', 5, 8, 2, '[{"instruction": "Heat skillet over medium heat with a touch of oil.", "step_number": 1}, {"instruction": "Place tortilla, scatter cheese, top with second tortilla.", "step_number": 2}, {"instruction": "Cook until golden and cheese is melted; flip once.", "step_number": 3, "time_minutes": 6}, {"instruction": "Cut into wedges; serve with salsa.", "step_number": 4}]', 'https://images.example.com/quesadilla.jpg', false, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000005-0000-0000-0000-000000000001', 'Pad Thai', 'Thai', 'Medium', 20, 15, 4, '[{"instruction": "Soak rice noodles in warm water until pliable.", "step_number": 1, "time_minutes": 15}, {"instruction": "Stir-fry shrimp and tofu; push aside, scramble egg.", "step_number": 2}, {"instruction": "Add noodles and sauce; toss with bean sprouts and chives.", "step_number": 3}, {"instruction": "Serve with crushed peanuts and lime.", "step_number": 4}]', 'https://images.example.com/pad-thai.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000005-0000-0000-0000-000000000002', 'Thai Green Curry', 'Thai', 'Medium', 15, 25, 4, '[{"instruction": "Fry green curry paste in coconut cream until fragrant.", "step_number": 1}, {"instruction": "Add chicken and remaining coconut milk; simmer.", "step_number": 2, "time_minutes": 15}, {"instruction": "Add Thai eggplant, bamboo shoots, fish sauce, palm sugar.", "step_number": 3}, {"instruction": "Finish with Thai basil; serve over jasmine rice.", "step_number": 4}]', 'https://images.example.com/green-curry.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000005-0000-0000-0000-000000000003', 'Tom Yum Soup', 'Thai', 'Easy', 10, 20, 4, '[{"instruction": "Simmer stock with lemongrass, galangal, kaffir lime leaves.", "step_number": 1}, {"instruction": "Add mushrooms, then shrimp; cook just until pink.", "step_number": 2}, {"instruction": "Off heat, add lime juice, fish sauce, chili paste.", "step_number": 3}]', 'https://images.example.com/tom-yum.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000005-0000-0000-0000-000000000004', 'Fresh Spring Rolls', 'Thai', 'Easy', 25, 0, 4, '[{"instruction": "Cook vermicelli noodles; drain.", "step_number": 1}, {"instruction": "Soften rice paper in warm water briefly.", "step_number": 2}, {"instruction": "Fill with shrimp, herbs, lettuce, noodles; roll tight.", "step_number": 3}, {"instruction": "Serve with peanut or hoisin dipping sauce.", "step_number": 4}]', 'https://images.example.com/spring-rolls.jpg', true, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL),
	('b0000005-0000-0000-0000-000000000005', 'Mango Sticky Rice', 'Thai', 'Easy', 240, 25, 4, '[{"instruction": "Soak glutinous rice for 4 hours.", "step_number": 1, "time_minutes": 240}, {"instruction": "Steam rice 20 minutes until tender.", "step_number": 2, "time_minutes": 20}, {"instruction": "Pour sweetened salted coconut cream over rice.", "step_number": 3}, {"instruction": "Serve with sliced ripe mango.", "step_number": 4}]', 'https://images.example.com/mango-sticky-rice.jpg', false, '2026-05-15 00:55:50.697125+00', NULL, NULL, NULL, NULL);
